mapper.select:
select t1.* from app_auction_up t1
 left join app_auction t2 on t2.id=t1.car_id
where t2.up_state='1' and t2.car_state='7' and t1.car_id=#{carId}

SELECT a.id as id, a.up_id as upId, a.create_time as createTime, a.up_time as upTime, a.end_time as endTime, a.update_time as updateTime, t2.up_state as upState, t2.car_state as carState, a.auction_state as auctionState, a.auction_days as auctionDays, a.transfer_state as transferState, -- a.audit_state as auditState, a.price as upId, a.service_fee as serviceFee, a.other_fee as otherFee, a.brand as upId, a.explain as upId, a.counselor_id FROM app_auction_up a left join app_auction t2 on a.car_id=t2.id
AND t2.car_state = #{auditState}
AND a.id = #{upId}
AND t2.up_state = #{upState}
ORDER BY ${page.orderBy}
